window.__QUIZ_DATA__=[{"id":"objective>Mathematics>2012>1","subject":"Mathematics","year":"2012","type":"Objective","topic":"NUMBER AND NUMERATION : FRACTIONS, DECIMALS AND APPROXIMATIONS","question":"Express 302.10495 correct to five significant figures.","images":[],"options":{"A":"302.10","B":"302.11","C":"302.105","D":"302.1049"},"answer":"A","explanation":"Given: 302.10495  The (n + 1)th digit is less than 5, hence take the first significant figures and drop the rest  302.10495 = 302.10 to 5.s.f","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2012>2","subject":"Mathematics","year":"2012","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Simplify:3&radic;5&nbsp; x 4&radic;6&nbsp;2&radic;2&nbsp; x 3&radic;3&nbsp;","images":[],"options":{"A":"&radic;2&nbsp;","B":"&radic;5&nbsp;","C":"2&radic;2&nbsp;","D":"2&radic;5&nbsp;"},"answer":"D","explanation":"Given: to simplify  3&radic;5&nbsp;\u00d74&radic;6&nbsp;2&radic;2&nbsp;\u00d73&radic;3&nbsp;=12&radic;30&nbsp;6&radic;6&nbsp;=2&radic;5&nbsp;","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>3","subject":"Mathematics","year":"2012","type":"Objective","topic":"NUMBER AND NUMERATION : RATIO, PROPORTIONS AND RATES","question":"In 1995, the enrollments of two schools X and Y were 1,050 and 1,190  respectively. Find the ration of the enrollments of X and Y.","images":[],"options":{"A":"50:11","B":"15:17","C":"13:55","D":"12:11"},"answer":"B","explanation":"Divide each enrolment by their common factor then the answer of each division gives the required ratio i.e x=105070=15andy=119070=17  \u2234 ratio of enrolment of x to y = 15 : 17","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2012>4","subject":"Mathematics","year":"2012","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBER BASES","question":"Convert 3510 to a number in base 2.","images":[],"options":{"A":"1011","B":"10011","C":"100011","D":"11001"},"answer":"C","explanation":"Given: to convert 3510 to a number in base 2  Divide 3510 through by 2 until it becomes zero (0), then write down the remainders from bottom to top as the required result.  2  2  2  2  2  2  .35  17 R 1    8 R 1    4 R 0   2 R 0   1 R 0   0 R 1    3510 \u21d2 1000112","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>5","subject":"Mathematics","year":"2012","type":"Objective","topic":"NUMBER AND NUMERATION : RATIO, PROPORTIONS AND RATES","question":"Mr. Manu travelled from Accra to Pamfokrom a distance of 720 km in 8 hours. What will be his speed in m/s?","images":[],"options":{"A":"25m/s","B":"150m/s","C":"250m/s","D":"500m/s"},"answer":"A","explanation":"Parameters given:  Distance, d = 720km  time, t = 8 hours   speed=dt=720km8hr=90kmhr-1  N.B: To convert from kmhr-1 to ms-1, multiply the value of the speed in kmhr-1 by 5/18  90kmhr-1=90\u00d7518=25ms","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>6","subject":"Mathematics","year":"2012","type":"Objective","topic":"NUMBER AND NUMERATION : SIMPLE INTEREST AND COMPOUND INTEREST","question":"If \u20a62,500.00 amounted to \u20a6 3,500.00 in 4 years at simple interest, find the rate at which the interest was charged.","images":[],"options":{"A":"5%","B":"7 1/2%","C":"8%","D":"10%"},"answer":"D","explanation":"Parameters given:  Amount, A = \u20a63500  Principal, P = \u20a62,500;   Time, T = 4 years  Rate, R = ?  Recall:  Interest (I) + Principal (P) = Amount (A)  I + P = A ---------------------- *  I = A - P  I = 3500 - 2500  I = 1000   Recall:  I=PRT100   \u20a61,000=\u20a62,500 x R x 4100   1000 = 100R    R=1000100=10%","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>7","subject":"Mathematics","year":"2012","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Solve for x in the equation: 1/x + 2/3x = 1/3","images":[],"options":{"A":"5","B":"4","C":"3","D":"1"},"answer":"A","explanation":"Given: the equation below  1x+23x=13   3 + 23x=13;    53x=13    3x = 15   x=153=5","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>8","subject":"Mathematics","year":"2012","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Simplify:54k2 - 63k + 1","images":[],"options":{"A":"6(1 - 3k2)","B":"6(3k2 - 1)","C":"6(3k - 1)","D":"6(1 - 3k)"},"answer":"C","explanation":"Given: to simplify  54k2 - 63l+1=6(9k2 - 1)3k + 1  6(3k-1)(3k+1)3k+1=6(3k-1)","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>9","subject":"Mathematics","year":"2012","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR INEQUALITIES","question":"Represent the inequality -7","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"B","explanation":"Given:  -7  -7   -4x + 9 \u2264 13 ----------- (2)    From (i)  -7 - 9  -16  4x > -16  x > -4 or -4  From (2)  4x \u2264 13 - 9  4x \u2264 4  x \u2264 1  combine the two answers -4","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>10","subject":"Mathematics","year":"2012","type":"Objective","topic":"ALGEBRAIC PROCESSES : CHANGE OF SUBJECT OF A FORMULA/RELATION","question":"Makepthesubjectoftherelation:q=3pr+s2","images":[],"options":{"A":"p=2q - rs6","B":"p = 2qr - sr - 3","C":"p=2qr - s6","D":"p=2qr - rs6"},"answer":"D","explanation":"Given:q=3pr+s2  q=2(3p) + r(s)2r  q=6p+rs2r  2qr = 6p + rs  2qr - rs = 6p  p=2qr-rs6","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2012>11","subject":"Mathematics","year":"2012","type":"Objective","topic":"ALGEBRAIC PROCESSES : SIMULTANEOUS LINEAR EQUATIONS IN TWO VARIABLES","question":"If x + y = 2y - x + 1 = 5, Find the value of x.","images":[],"options":{"A":"3","B":"2","C":"1","D":"-1"},"answer":"B","explanation":"Given: the expression below  x + y = 2y - x + 1 = 5 {split the expression into two}  x + y = 2y - x + 1 ------------- (1)  x + y = 5 ------------- (2)  Equation (1) becomes  2x - y = 1 --------------------- (3)  combine (2) and (3) {add (2) and (3)}  3x = 6  x = 2  substitute for x = 2 in (2)  \u2234 2 + y = 5  y = 3  \u2234 (x, y) = (2, 3)","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>12","subject":"Mathematics","year":"2012","type":"Objective","topic":"ALGEBRAIC PROCESSES : FORMULATION AND EVALUATION OF ALGEBRAIC PROCESSES","question":"The sum of 12 and one third of n is 1 more than twice n. Express the statement in the form of an equation.","images":[],"options":{"A":"12n -6 = 0","B":"3n - 12 = 0","C":"2n - 35 = 0","D":"5n - 33 = 0"},"answer":"D","explanation":"Express the question in equation form  12+13n=2n+1----------------*  Multiply through by 3  36 + n = 6n + 3  5n = 33  5n - 33 = 0","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2012>13","subject":"Mathematics","year":"2012","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR INEQUALITIES","question":"Solve the Inequality: -m2-54\u22645m12-76","images":[],"options":{"A":"m \u2265 5/4","B":"m \u2264 5/4","C":"m \u2265 -1/11","D":"m \u2264 -1/11"},"answer":"C","explanation":"-2m-54\u22643m-1412  12(-2m-5) \u2264 4 (5m-14)  -24m - 60 \u2264 4 (5m-14)  -24m-60 \u226420m - 56  -24m - 20m \u2264 -56 + 60  -44m \u2264 4  m\u2265-444  m\u2265-111","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2012>14","subject":"Mathematics","year":"2012","type":"Objective","topic":"MENSURATION : AREAS","question":"The curved surface area of a cylindrical tin is 704cm2. If the radius of its base is 8cm. Find the height [Take \u03c0 = 22/7]","images":[],"options":{"A":"14cm","B":"9cm","C":"8cm","D":"7cm"},"answer":"A","explanation":"Parameters given:  Curved Surface Area= 704cm2  Base radius, r = 8cm  Height, h = ?  Recall: Curved Surface Area of a cylinder = 2\u03c0rh  \u2234704=2\u00d7227\u00d78\u00d7h  704=447\u00d78h  704 \u00d7 7 = 352h  h = 14.0cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>15","subject":"Mathematics","year":"2012","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"The lengths of the minor and major arcs of a circle are 54cm and 126cm respectively. Calculate the angle of the major sector.","images":[],"options":{"A":"306o","B":"252o","C":"246o","D":"234o"},"answer":"B","explanation":"Parameters given:  Length of major arc = 126cm  Length of minor arc = 54cm    N.B: Minor arc + major arc = Circumference  \u2234 54 + 126 = Circumference  180 = 2\u03c0r  180=2\u00d7227\u00d7r  180 \u00d7 722 \u00d7 2=r  r=126044=31511=28.64cm  Recall:Lengthofarc=\u03b8360\u00d72\u03c0r  Lengthofmajorarc=126=\u03b8360\u00d7(2\u00d7227\u00d728.64)  126=\u03b8360\u00d7180  \u03b8 = 252\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>16","subject":"Mathematics","year":"2012","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"A sector of a circle which subtends 172o at the centre of the circle has a perimeter of 600cm. Find, correct to the nearest cm, the radius of the circle. [Take \u03c0 = 22/7]","images":[],"options":{"A":"120cm","B":"116cm","C":"107cm","D":"100cm"},"answer":"A","explanation":"Parameters given:  Angle, \u03b8 = 172\u00b0  Perimeter of sector, P = 600cm  Radius, r = ?    Recall: Perimeter of sector = 2r + L  P=2r + \u03b8360x2\u03c0r;   600=2r+172360\u00d72\u00d7227\u00d7r  600=2r+17290\u00d7117\u00d7r  600 = 2r + 3r  600 = 5r   r = 120cm","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2012>17","subject":"Mathematics","year":"2012","type":"Objective","topic":"TRIGONOMETRY : ANGLES OF ELEVATION AND DEPRESSION","question":"In the diagram, |QR| = 10m,   |SR| = 8m, \u2220QPS = 30o    \u2220QRP = 90o and |PS| = x. Find x.","images":["data:image/png;base64,"],"options":{"A":"1.32m","B":"6.32m","C":"9.32m","D":"17.32m"},"answer":"C","explanation":"Given: the diagram in the question    Recall:tan\u03b8=oppadj  tan30\u00b0=10x+8  1&radic;3&nbsp;=10x+8  x + 8 = 10&radic;3&nbsp;  x + 8 = 17.32  x = 9.32m","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2012>18","subject":"Mathematics","year":"2012","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"In \u0394XYZ, /XY/ = 8cm , /YZ/ = 10cm and /XZ/ = 6cm. Which of these relations is true?","images":[],"options":{"A":"/XY/ + /YZ/ = /XZ/","B":"/XY/ - /YZ/ = /XZ/","C":"/XZ/2 = /YZ/2 - /XY/2","D":"/YZ/2 = /XZ/2 - /XY/2"},"answer":"C","explanation":"Represent the information in the question diagrammatically,    From close observation, the triangle above is a right angled triangle. This is because e10cm, 8cm and 6cm are Pythagora's triples.  YZ2 = XY2 + xz2   XZ2 = YZ2 - XY2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>19","subject":"Mathematics","year":"2012","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram, O is the centre of the circle PQRS and \u2220PSR = 86o. If \u2220POR = xo, Find x.","images":["data:image/png;base64,"],"options":{"A":"274","B":"172","C":"129","D":"86"},"answer":"B","explanation":"Recall: The angle subtended by an arc at the centre  = 2 x angle at other points on the circumference  xo = 86 x 2 = 172o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>20","subject":"Mathematics","year":"2012","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"The diagram is a circle centre O. If \u2220SPR = 2m and \u2220SQR = n.   Express m in terms of n.","images":["data:image/png;base64,"],"options":{"A":"m = n/2","B":"m = 2n","C":"m = n - 2","D":"m = n + 2"},"answer":"A","explanation":"If \u2220SPR = 2m then \u2220SQR = 2m but  \u2220 but \u2220SQR was n     \u2234n=2m;m=n2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>21","subject":"Mathematics","year":"2012","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram, MQ//RS. \u2220TUV = 70o and \u2220RLV = 30o. Find the  value of x.","images":["data:image/png;base64,"],"options":{"A":"150o","B":"110o","C":"100o","D":"95o"},"answer":"C","explanation":"Given: the diagram in the question    N.B: y = 30 (corresponding angles)  p = y = 30\u00b0 (vertically opposite angle)  p + q + 70\u00b0 = 180\u00b0 (sum of angles in a \u0394)  30\u00b0 + 70\u00b0 + q = 180\u00b0  q = 80\u00b0  q + x = 180\u00b0 (sum of angles on a straight line)  80\u00b0 + x = 180\u00b0  x = 100\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>22","subject":"Mathematics","year":"2012","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram, MN, PQ and RS are three intersecting straight lines. Which of the following statements is/are true?   I. t = y,  II. x + y + z + m = 180o  III. x + m + n = 180o    IV. x + n = m + z","images":["data:image/png;base64,"],"options":{"A":"I and IV only","B":"II only","C":"III only","D":"IV only"},"answer":"C","explanation":"m + y + x = 180o (sum of \u2220s on straight line); y = n (vertically opposite angle)  \u2234 m + n + x = 180o","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2012>23","subject":"Mathematics","year":"2012","type":"Objective","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"If cos(x + 40)o = 0.0872, what is the value of x?","images":["data:image/png;base64,"],"options":{"A":"85o","B":"75o","C":"65o","D":"45o"},"answer":"D","explanation":"cos(x + 40o) = 0.0872;  let x + 40o = P   cosP = 0.0872  P = cos-10.0872;    P = 85\u00b0  x + 40o = 85o;   x = 85o - 40o    x = 45o","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2012>24","subject":"Mathematics","year":"2012","type":"Objective","topic":"TRIGONOMETRY : ANGLES OF ELEVATION AND DEPRESSION","question":"A kite flies on a taut string of length 50m inclined at an angle of 54o to the horizontal ground. The height of the kite above the ground is","images":[],"options":{"A":"50tan30o","B":"50sin54o","C":"50 tan 54o","D":"50sin36o"},"answer":"B","explanation":"The information in the question can be represented diagrammatically as thus:    sin54=h50  h = sin54 \u00d7 50  h = 40.5m","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>25","subject":"Mathematics","year":"2012","type":"Objective","topic":"TRIGONOMETRY : BEARINGS","question":"The positions of three ships P, Q and R at sea are illustration in the diagram. The arrows indicated the North direction. The bearing of Q from P is 050o and \u2220PQR = 72o.   Calculate the bearing of R and Q.","images":["data:image/png;base64,"],"options":{"A":"130o","B":"158o","C":"222o","D":"252o"},"answer":"B","explanation":"Given: the diagram in the question     72 + 40 +  112 +     The bearing of R from Q = 90\u00b0 + 68\u00b0 = 158\u00b0","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2012>26","subject":"Mathematics","year":"2012","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"Given that the mean of the scores 15, 21, 17, 26, 18 and 29 is 21. Calculate the standard deviation of the scores.","images":[],"options":{"A":"&radic;10&nbsp;","B":"4","C":"5","D":"&radic;30&nbsp;"},"answer":"C","explanation":"Given: the set of data below  15, 21, 17, 26, 18 and 29  Mean, X\u0305 = 21  Standard deviation, S.D = ?  Recall:   S.D=&radic; \u2211 (x - X\u0305)2N&nbsp;   S.D=&radic;62+02+42+52+32+826&nbsp;   S.D=&radic;1506&nbsp;=5","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>27","subject":"Mathematics","year":"2012","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"A bag contains 4 red and 6 black balls of the same size . If the balls are shuffled briskly and two balls are drawn one after the other without replacement, find the probability of picking balls of different colours.","images":[],"options":{"A":"8/15","B":"13/25","C":"11/15","D":"13/15"},"answer":"A","explanation":"Parameters given:  Number of red balls = 4  Number of black balls = 6  \"Two balls are drawn without replacement\"  Probability of picking balls of different calls = ?  BR or RB   =Prob(410\u00d769)+Prob(610\u00d749)=2490+2490    =4890=1630=815","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>28","subject":"Mathematics","year":"2012","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The bar chart shows the frequency distribution of marks scored by students in a class test. Use the bar chart to answer this question.    How many students are in the class?","images":["data:image/png;base64,"],"options":{"A":"10","B":"24","C":"25","D":"30"},"answer":"C","explanation":"The number of students in the class = 6 + 8 + 6 + 5 = 25","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2012>29","subject":"Mathematics","year":"2012","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The bar chart shows the frequency distribution of marks scored by students in a class test. Use the bar chart to answer this question.  Calculate the mean of the distribution.","images":["data:image/png;base64,"],"options":{"A":"6.0","B":"3.0","C":"2.4","D":"1.8"},"answer":"C","explanation":"xFFx1  2  3  46  8  8  56  16  18  20    mean x = \u2211fx/\u2211f = 60/25    x = 2.4","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>30","subject":"Mathematics","year":"2012","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The bar chart shows the frequency distribution of marks scored by students in a class test. Use the bar chart to answer this question.  What is the median of the distribution?","images":["data:image/png;base64,"],"options":{"A":"2","B":"4","C":"6","D":"8"},"answer":"A","explanation":"median=N+12th=25+12th=26th2=13th   the 13th is 2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>31","subject":"Mathematics","year":"2012","type":"Objective","topic":"NUMBER AND NUMERATION : LOGARITHMS","question":"Which of these statements about y = 8&radic;m&nbsp; is correct?","images":[],"options":{"A":"log y = log8 \u00d7 log &radic;m&nbsp;","B":"log y = 3log2 \u00d7 1/2log m","C":"log y = 3 log 2 - 1/2log m","D":"log y = 3log2 + 1/2log m"},"answer":"D","explanation":"Given: y = 8&radic;m&nbsp;  y = 8m1/2 ---------- * (from indices)  Add log to both sides   logy = log8m1/2  Recall: logab = loga + logb  logy = log8 + logm1/2 ---------------   Recall: logan = nloga  logy = log 8 + 1/2 logm ----------------   logy = log23 + 1/2 log m  logy=3log2+12logm","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2012>32","subject":"Mathematics","year":"2012","type":"Objective","topic":"ALGEBRAIC PROCESSES : SIMULTANEOUS LINEAR EQUATIONS IN TWO VARIABLES","question":"If x + 0.4y = 3 and y = 1/2x, find the value of (x + y)","images":[],"options":{"A":"1 1/2","B":"2 1/2","C":"33/4","D":"5"},"answer":"C","explanation":"Given: x + 0.4y = 3 ------------------ (1)  y=12x------------------------(2)  substitutefory=12xin(i)  x+0.4(12x)=3  x + 0.2x = 3  1.2x = 3  x = 2.5  y=12(2.5)=1.25  \u2234x+y=2.5+1.25=3.75=334","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>33","subject":"Mathematics","year":"2012","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Express3-x - yyasasinglefraction","images":[],"options":{"A":"3xy/y","B":"x-4yy","C":"4y + xy","D":"4y - xy"},"answer":"D","explanation":"Given:3-x - yy,  31-x - yy    3y - (x - y)y   3y - x + yy=4y - xy","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>34","subject":"Mathematics","year":"2012","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Findthecoefficient of mintheexpansion of (m2-114)(m+23)","images":[],"options":{"A":"-1/6","B":"-1/2","C":"-1","D":"-1 1/6"},"answer":"D","explanation":"m2-114xm+23   m2-32\u00d7m1+23   thecoefficientofmcanbeobtainedbymultiplyingm2by23and -32bym,andtakingthesumoftheresults  \u2234(m2\u00d723)+(-32\u00d7m1)  2m - 9m6   =-7m6    the co-efficient of m =-116","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2012>35","subject":"Mathematics","year":"2012","type":"Objective","topic":"PLANE GEOMETRY : ANGLES AND INTERCEPTS ON PARALLEL LINES","question":"In the diagram, MN//PO, \u2220PMN = 112o, \u2220PNO = 129o, \u2220NOP = 37o and \u2220MPN = yo. Find the value of y.","images":["data:image/png;base64,"],"options":{"A":"51o","B":"54o","C":"56o","D":"68o"},"answer":"B","explanation":"Given: the diagram below    N.B: MN is parallel to PO    112 + m = 180\u00b0 (sum of angles on a straight line)   m = 68\u00b0  N.B: m =   In \u0394NPO; \u2220NPO + \u2220PNO + \u2220NOP = 180o (sum of interior angle in a \u0394);    i.e NPO + 129 + 37 = 180o    \u2234 \u2220NOP = 180 - (129 + 37) = 14o;    \u2220MNP = \u2220NOP = 14o (alternate angles);   N.B: y +  y + 14 = 68  y = 54o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>36","subject":"Mathematics","year":"2012","type":"Objective","topic":"NUMBER AND NUMERATION : SETS","question":"If P = {prime factors of 210} and Q = {prime numbers less than 10}, find P\u2229Q.","images":[],"options":{"A":"{1,2,3}","B":"{2,3,5}","C":"{1,3,5,7}","D":"{2,3,5,7}"},"answer":"D","explanation":"Parameters given:  P = {Prime factors of 210}  Q = {Prime numbers less than 10}  N.B: Prime factors of 210 = 2, 3, 5, 7,    Prime numbers less than 10 = 2, 3, 5, 7;   P = {2, 3, 5, 7}  Q = {2, 3, 5, 7}  P \u2229 Q = {2, 3, 5, 7}","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2012>37","subject":"Mathematics","year":"2012","type":"Objective","topic":"NUMBER AND NUMERATION : PROFIT AND LOSS","question":"Alfred spent 1/4 of his money on food, 1/3 on clothing and saved the rest. If he saved \u20a672,000.000, how much did he spend on food?","images":[],"options":{"A":"\u20a643,200.00","B":"\u20a643,000.00","C":"\u20a642,200.00","D":"\u20a640,000.00"},"answer":"A","explanation":"Let Alfred's total money be x  -Totalamountspentonfood=14x  -Totalamountspentonclothing=13x  - Total amount he saved = \u20a672,000 (the rest)  x=14x+13x+72,000  \u2234x=7x12+72,000  5x12=72,000  x = 72,000 \u00d7 2.4  x = 172,800  the total amount of money he has = \u20a6172,800  \u223414\u00d7172,800wasspentonfood  \u20a643,200","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>38","subject":"Mathematics","year":"2012","type":"Objective","topic":"NUMBER AND NUMERATION : LAWS OF INDICES","question":"Solve: (27125)-1/3 x (49)1/2","images":[],"options":{"A":"10/9","B":"9/10","C":"2/5","D":"12/125"},"answer":"A","explanation":"Given:  (27125)-1/3\u00d7(49)1/2  Recall:(ab)-n=(ba)n  (12527)1/3\u00d7(49)1/2  Recall:(ab)1/n=n&radic;ab&nbsp;  &#179&radic;12527&nbsp;\u00d7&radic;49&nbsp;   1/3 x 5/1 x 2/3 = 10/9","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2012>39","subject":"Mathematics","year":"2012","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"The sum of the interior angles of regular polygon is 1800o. How many sides has the polygon?","images":[],"options":{"A":"16","B":"12","C":"10","D":"8"},"answer":"B","explanation":"Parameters given:  The sum of the interior angles of a regular polygon = 1800\u00b0  Recall: The sum of the interior angles of an n-sided regular polygon = 180n - 360  \u2234 1800 = 180n -360  180n = 1800 + 360  180n = 2160  n = 12","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>40","subject":"Mathematics","year":"2012","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"The diagram is a circle with centre O. PRST are points on the circle. Find the value of \u2220PRS","images":["data:image/png;base64,"],"options":{"A":"144o","B":"72o","C":"40o","D":"36o"},"answer":"A","explanation":"2x + 8x = 360  10x = 360  x = 36  1/2 x 8x = 4x  4 x 36","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>41","subject":"Mathematics","year":"2012","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"The diagram is a circle of radius |QR| = 4cm. TR is a tangent to the circle at R. If TPO = 120o, find |PQ|","images":["data:image/png;base64,"],"options":{"A":"2.32cm","B":"1.84cm","C":"0.62cm","D":"0.26cm"},"answer":"C","explanation":"\u2220OPR = 180 - 1200 (\u2220s on a straight line) = 600;    |OR| = 4cm(radius);    In right \u2220\u0394OPR;   sin60o=ORPO=4PO    PO=4sin60o=40.8660;   PO = 4.62cm;    But PQ + OQ = PO   \u2234 PQ = PO - OQ = 4.62 - 4 = 0.62cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>42","subject":"Mathematics","year":"2012","type":"Objective","topic":"ALGEBRAIC PROCESSES : FUNCTIONS AND RELATIONS","question":"If x and y are variables and k is a constant, which of the following describes an inverse relationship between x and y?","images":[],"options":{"A":"y = kx","B":"y = k/x","C":"y = k&radic;x&nbsp;","D":"y = x + k"},"answer":"B","explanation":"Given:x\u221d1y;    x=kyory\u221d1x;    y=kx","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2012>43","subject":"Mathematics","year":"2012","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram, |SR| = |QR, \u2220SRP = 65o and \u2220RPQ = 48o. Find \u2220PRQ","images":["data:image/png;base64,"],"options":{"A":"65o","B":"45o","C":"25o","D":"19o"},"answer":"D","explanation":"Given: the diagram below    48\u00b0 =  N.B: \u0394SQR is an isosceles triangle    48\u00b0 + 48\u00b0 +  96\u00b0 +   N.B:  84 = 65 +  o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>44","subject":"Mathematics","year":"2012","type":"Objective","topic":"ALGEBRAIC PROCESSES : GRAPHS OF LINEAR AND QUADRATIC FUNCTIONS","question":"The graph is that of y = 2x2 - 5x - 3.    For what values of x will y be negative?","images":["data:image/png;base64,"],"options":{"A":"-12\u22643","B":"-12x\u22643","C":"-12x3","D":"-12\u2264x\u22643"},"answer":"C","explanation":"2x2 - 5x - 3 = 0   2x2 - 6x + x - 3 = 0    2x(x - 3) + 1(x - 3) = 0    (2x + 1)(x- 3) = 0    2x + 1 = 0 or x - 3 = 0    2x = -1 or x - 3 = 0    x=-12orx=3   \u2234-12x3","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2012>45","subject":"Mathematics","year":"2012","type":"Objective","topic":"ALGEBRAIC PROCESSES : DRAWING TANGENTS TO CURVES TO DETERMINE THE GRADIENT AT A GIVEN POINT","question":"The graph is that of y = 2x2 - 5x - 3.   The graph is that of y = 2x2 - 5x - 3.   What is the gradient of y = 2x2 - 5x - 3 at the point x = 4?","images":["data:image/png;base64,"],"options":{"A":"11.1","B":"10.5","C":"10.3","D":"9.9"},"answer":"A","explanation":"The gradient of y = 2x2 - 5x - 3 at the point x = 4 is 11.1.","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2012>46","subject":"Mathematics","year":"2012","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"The diagram is a polygon. Find the largest of its interior angles.","images":["data:image/png;base64,"],"options":{"A":"30o","B":"100o","C":"120o","D":"150o"},"answer":"D","explanation":"Note that the largest of the interior is one that has the smallest exterior angle, i.e x  Recall: the sum of interior angles of any polygon = 360o;    i.e 3x + 2x + 2x + x + 4x = 360o;    12x = 360   x=36012   x = 30o  Also recall: the sum of an interior angle and its adjacent exterior angle = 180\u00b0   x + Aext = 180    30o + Aext = 180o   Aext = 180 - 30   Aext = 150o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>47","subject":"Mathematics","year":"2012","type":"Objective","topic":"MENSURATION : VOLUMES","question":"The volume of a cuboid is 54cm3. If the length, width and height of the cuboid are in the ratio 2:1:1 respectively. Find its total surface area.","images":[],"options":{"A":"108cm2","B":"90cm2","C":"80cm2","D":"72cm2"},"answer":"B","explanation":"Parameters given:  Volume of a cuboid = 54cm3  Ratio of L to B to H = 2 : 1 : 1  Recall: V = L \u00d7 B \u00d7 H ------------------ *  Let the common factor for the ration = x  2x \u00d7 x \u00d7 x = 54  2x3 = 54  x3 = 27  \u2234 x = 3   L = 6cm, B = 3cm, H = 3cm.  Recall: Total surface area of a cuboid = 2lb + 2lh + 2bh ---------------- **  Total Surface Area = 2(6 \u00d7 3) + 2(6 \u00d7 3) + 2(3 \u00d7 3)  TSA = 2(18) + 2(18) + 2(9)  TSA = 36 + 36 + 18 = 90cm2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>48","subject":"Mathematics","year":"2012","type":"Objective","topic":"MENSURATION : AREAS","question":"A side and a diagonal of a rhombus are 10cm and 12cm respectively. Find its area.","images":[],"options":{"A":"20cm2","B":"24cm2","C":"48cm2","D":"96cm2"},"answer":"D","explanation":"Given:  The length of a side of the rhombus = 10cm  the length of a diagonal of the rhombus = 12cm  Area of the rhombus = ?  Diagrammatically, we have    \u0394AOB is a right-angled triangle  Note that the diagonals of a rhombus intersect at angle 90\u00b0, i.e right-angle.  |AO| = 8cm, using pythagora's theorem   There are four right-angled triangles within the rhombus   Area of rhombus = 4 \u00d7 Area of right -angled triangle   Areaofrhombus=4\u00d712\u00d78\u00d76  A = 2 \u00d7 48 = 96cm2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>49","subject":"Mathematics","year":"2012","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Factorise completely: 32x2y - 48x3y3","images":[],"options":{"A":"16x2y(2 - 3xy2)","B":"8xy(4x - 6x2y2)","C":"8x2y(4 - 6xy2)","D":"16xy(2x - 3x2y2)"},"answer":"A","explanation":"Given: to factorize 32x2y - 48x3y3;   the HCF is 16x2y   16x2y(2 - 3xy2)","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2012>50","subject":"Mathematics","year":"2012","type":"Objective","topic":"NUMBER AND NUMERATION : SEQUENCE AND SERIES","question":"The nth term of a sequence is Tn = 5 + (n - 1)2. Evaluate T4 - T6","images":[],"options":{"A":"30","B":"16","C":"-16","D":"-30"},"answer":"C","explanation":"T4 = 5 + (4 - 1)2; where n = 4; = 5 + (3)2 = 5 + 9    =  14;   T6 = 5 + (6 - 1)2;   where n = 6; 5 + (5)2    = 5 + 25 = 30;    T4 - T6 = 14 - 30 = -16","marks":"1","difficulty":"1"}];